- 예시: apple → 사과, banana → 바나나, strawberry → 딸기

한국어 번역:`;

      const translatedText = await callGeminiAPI(prompt);
      const cleanTranslation = translatedText.replace(/[^\가-힣]/g, '').trim();
      
      if (cleanTranslation && cleanTranslation.length > 0) {
