        originalKeyword: 'coconut',
        description: '코코넛 + 음료키워드 → 코코넛밀크'
      },
      
      // 오렌지 관련 주스 패턴들
      {
        pattern: /(오렌지|ORANGE|orange).*?(100%|주스|juice|JUICE|ml|mL|ML|리터|L|l)/i,
